  majorCurrencyAmount: string | number;
  fractionDigits: number;
}): number {
  const amount =
    typeof majorCurrencyAmount === "string"
      ? Number(majorCurrencyAmount.replace(/[^\d.]/g, ""))
      : majorCurrencyAmount;

  return Math.round(amount * 10 ** fractionDigits);
}

export function getFractionDigitsForCurrency(currencyCode: string): number {
  const formatter = new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: currencyCode,
  });

  return formatter.resolvedOptions().maximumFractionDigits ?? 0;
}

export function formatCurrency(
  amount: number | undefined,
  { includeCurrencySymbol = true }: { includeCurrencySymbol?: boolean } = {},
) {
  if (amount === undefined) {
    return "—";
  }

  const currencyFormatter = new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
  });

  const formatted = currencyFormatter.format(
    convertMinorToMajor({
      minorCurrencyAmount: amount,
      fractionDigits: getFractionDigitsForCurrency("USD"),
    }),
  );

  return includeCurrencySymbol ? formatted : formatted.replace(/[^\d.]/g, "");
}

export function FormattedDate({
  date,
  options = {
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
    hour12: true,
    timeZoneName: "short",
  },
}: {
  date: string | undefined;
  options?: Intl.DateTimeFormatOptions;
}) {
  // When SSR'ing, the timezone is UTC. To avoid hydration errors, we first
  // render the date in UTC, then update it to the client's timezone when
  // the component mounts. This reduces flickering since the element is rendered
  // with roughly the same width of text in both cases.
  const [isHydrated, setIsHydrated] = useState(
    typeof window === "undefined" ? false : window.__HYDRATED__,
  );
  const [displayDate, setDisplayDate] = useState<string>(
    date
      ? isHydrated
        ? new Date(date).toLocaleString("en-US", {
            ...options,
          })
        : new Date(date).toLocaleString("en-US", {
            timeZone: "UTC",
            ...options,
          })
      : "—",
  );

  useEffect(() => {
    setIsHydrated(true);
  }, []);

  useEffect(() => {
    if (!date) {
      return;
    }

    setDisplayDate(new Date(date).toLocaleString("en-US", options));
  }, [date, options]);

  return (
    <span className={isHydrated ? "visible" : "invisible"}>{displayDate}</span>
  );
}

export function formatStringFromServer(string: string | undefined) {
  if (typeof string !== "string" || string === "") {
    return "—";
  }

  return string
    .replace(/_/g, " ")
    .replace(/([a-zA-Z])\.([a-zA-Z])/g, "$1 $2")
    .replace(/\b\w/g, (char) => char.toUpperCase())
    .replace(/echeck/gi, "eCheck");
}

export function escapeForRegex(str: string) {
  return str.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

export function sortByCreatedAt(
  a: { created_at?: string },
  b: { created_at?: string },
) {
  if (!a.created_at || !b.created_at) {
    return 0;
  }

  return new Date(b.created_at).getTime() - new Date(a.created_at).getTime();
}
